#import "XPPollingProxyBridge.h"

@implementation XPPollingProxyBridge

+ (instancetype)shared {
    static XPPollingProxyBridge *sharedInstance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        sharedInstance = [[XPPollingProxyBridge alloc] init];
    });
    return sharedInstance;
}

- (NSString *)abilityCarTypeCode {
    return XPVehicleSDK.currentAbilityConfig.carTypeCode;
}

- (void)pollingLockResultWithIsSuccess:(BOOL)isSuccess {
    [XPToast showMessage:isSuccess? @"车门已上锁" : @"上锁失败"];
}

- (void)pollingUnlockResultWithIsSuccess:(BOOL)isSuccess {
    [XPToast showMessage:isSuccess? @"车门已解锁" : @"解锁失败"];
}


@end

