#ifndef PLXPPollingDefined_h
#define PLXPPollingDefined_h

#define kBleKeyPollingConfigCode        @"pollingConfig"
#define kBleKeyPollingLockSound @"com.xiaopeng.xppolling.BleKeyPollingLockSound"

//是否兜底
#define kBleKeyPollingIsRemedy  @"com.xiaopeng.xppolling.BleKeyPollingIsRemedy"

#define kSystemBLESwitchIsOn @"systemBLESwitchIsOn"

#define ALL_WORK_KEY_EXIST 0 //万能钥匙开关，测试用

#define kAllWorkMessage  @"WFBCS1RIAQAAgmB2UQ8AAUtJABA1D//tsCJaELF76kk8LUkURUQAECvHR5hZKP1lh7E6Bu9ZjbxTTgBGMEQCIE4w3sdxBpVviDzbsI1cYbRn9gMwpMZbaaP8i4uT9q+DAiB3v0vkM/w+aNnPhhzzbRg4ay3v4mk6clFbkI8SUjm5Vw=="


#define kLoginBigScreenSetting @"com.xiaopeng.blekeysetting.LoginBigScreenSetting"
#define kScanSetting  @"scanSetting"
#define kSlaveAuthSetting  @"slaveAuthSetting"
#define kConfigSetting @"configSetting"
#define kConfigPollingSetting @"configPollingSetting"
#define kOtaTestSetting @"otaTestSetting"

#define kPermissionPopup @"com.xiaopeng.blekeysetting.PermissionPopup"

#define kNotificationWatchLockForbidPolling @"kNotificationWatchLockForbidPolling"
#define kWatchLock @"watchLock"

typedef NS_ENUM(NSUInteger,PLPollingRunMode) {
    PLPollingRunModeNone= 0,                 // 解锁和闭锁都不开启
    PLPollingRunModeUnLock,                  // 只开启解锁
    PLPollingRunModeLock,                    // 只开启闭锁
    PLPollingRunModeLockAndUnlock            // 解锁和闭锁都开启
};

typedef NS_ENUM(NSInteger,PLPollingAction) {
    PLPollingActionIdle = 0,         // 无操作
    PLPollingActionLock = 1,          // 上锁
    PLPollingActionUnlock,            // 解锁
    PLPollingActionInCar,             // 车内
    PLPollingActionEnable,            // 解锁授权
    PLPollingActionDisable            // 解锁解除授权
};

typedef NS_ENUM(NSInteger,PLPollingCmdType) {
    PLPollingCmdTypePollingInCar = 0,                 // Polling定位在车内
    PLPollingCmdTypePollingUnlock = 1,                // Polling解锁
    PLPollingCmdTypePollingLock = 2,                  // Polling闭锁
    PLPollingCmdTypePollingEnable,                    // Polling授权解锁
    PLPollingCmdTypePollingDisable,                   // Polling取消授权解锁
    PLPollingCmdTypePollingTrunkEnable,               // Polling授权解锁后备箱
    PLPollingCmdTypePollingTrunkDisable,              // Polling取消授权解锁后备箱
    PLPollingCmdTypePollingChargePortEnable,          // Polling授权解锁充电枪
    PLPollingCmdTypePollingChargePortDisable,         // Polling取消授权解锁充电枪
    PLPollingCmdTypePollingHandUnlockCar,             // 20min钟后，手动解锁车辆
    PLPollingCmdTypePollingHandUnlockTrunk,           // 20min钟后，手动解锁车辆
    PLPollingCmdTypePollingHandUnlockChargePort       // 20min钟后，手动解锁车辆
};


#endif /* XPPollingDefined_h */

