@implementation PLXPPollingHandler

- (instancetype)init {
    if (self = [super init]) {
        _distanceLevel = PLBLEKeyDistanceLevelInitCircle;
        _lastDistanceLevel = PLBLEKeyDistanceLevelInitCircle;
        _lastDistance = PL_INVAILD_DISTANCE;
        _currentDistance = PL_INVAILD_DISTANCE;
        _pollingUnlockInterval = 2;
        _pollingLockInterval = 2;
        _pollingTrunckEnableInterval = 2;
        _pollingTrunckDisableInterval = 2;
    }
    return self;
}

- (void)dealloc {
}


- (void)initPolling {
    self.pollingInited = YES;
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onAppTerminateAction:) name:UIApplicationWillTerminateNotification object:nil];
}

- (void)deinitPolling {
    self.pollingInited = NO;
    self.distanceLevel = PLBLEKeyDistanceLevelInitCircle;
    self.lastDistanceLevel = PLBLEKeyDistanceLevelInitCircle;
    self.currentDistance = PL_INVAILD_DISTANCE;
    self.lastDistance = PL_INVAILD_DISTANCE;
    self.isWatchLocked = NO;
    [self disableUnlockTimer];
    [self disableLockTimer];
    _unlockOperateTime = 0;
    _unlockOperateTimestamp = 0;
    _lockOperateTime = 0;
    _lockOperateTimestamp = 0;
    self.monitorLock = NO;
    self.monitorUnlock = NO;
    self.monitorDoorOpen = NO;
