- (void)setUnlockOperateTime:(NSInteger)unlockOperateTime{
    _unlockOperateTime = unlockOperateTime;
    [self disableUnlockTimer];
    if(unlockOperateTime > 0) {
        _unlockOperateTimestamp = [[NSDate date] timeIntervalSince1970];
        DLogTagInfo(kBLEKeyPollingTag, @"设置polling解锁操作限制,%ld", unlockOperateTime);
        @weakify(self);
        self.unlockTimer = [NSTimer bl_scheduledTimerWithTimeInterval:unlockOperateTime block:^(NSTimer *timer) {
            @strongify(self)
            DLogTagInfo(kBLEKeyPollingTag, @"重置polling解锁操作限制");
            self.unlockOperateTime = 0;
        } repeats:NO];
    }
}

