#pragma mark — tool
- (NSString *)floatToFixedString:(float)value
{
    NSString * str = [NSString stringWithFormat:@"%.0f", value];
    if (2 == [str length])
    {
        str = [NSString stringWithFormat:@" %@", str];
    }
    if (1 == [str length])
    {
        str = [NSString stringWithFormat:@"  %@", str];
    }

    return str;
}

- (void)bleKeyLocationStr {
    NSString *distanceLevelStr = @"";
    switch(self.distanceLevel) {
        case PLBLEKeyDistanceLevelInCar:
            distanceLevelStr = @"车内";
            break;
        case PLBLEKeyDistanceLevelOneMeterCircle:
            distanceLevelStr = @"1m圈";
            break;
        case PLBLEKeyDistanceLevelUnlockCircle:
            distanceLevelStr = @"解锁圈";
            break;
        case PLBLEKeyDistanceLevelEnableCircle:
            distanceLevelStr = @"授权圈";
            break;
        case PLBLEKeyDistanceLevelBuffCircle:
            distanceLevelStr = @"过渡圈";
            break;
        case PLBLEKeyDistanceLevelLockCircle:
            distanceLevelStr = @"闭锁圈";
            break;
        case PLBLEKeyDistanceLevelWelcomeCircle:
            distanceLevelStr = @"迎宾圈";
            break;
        case PLBLEKeyDistanceLevelConnectCircle:
            distanceLevelStr = @"连接圈";
            break;
        case PLBLEKeyDistanceLevelInitCircle:
            distanceLevelStr = @"分圈初始化";
            break;
        default:
            break;
    }
    DLogTagInfo(kBLEKeyPollingTag, @"PLogic，现在的圈是:%@", distanceLevelStr);
}



