362	- (void)revealHttpLock {
363	    if(self.pollingRunMode != PLPollingRunModeLockAndUnlock && self.pollingRunMode != PLPollingRunModeLock){
364	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>不是Polling解闭锁,或不是Polling闭锁，不发4G闭锁");
365	        return;
366	    }
367	    if (self.beforeDisconnectTemporaryLockState == XPVehicleTempLockStateActive) {
368	        DLogTagInfo(kBLEKeyPollingTag, @"临停状态，不发4G闭锁");
369	        return;
370	    }
371	    
372	    if(self.beforeDisconnectDoorLockState == XPVehicleDoorLockStateLocked){
373	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>车门已锁，不发4G闭锁");
374	        return;
375	    }
376	    if(self.beforeDisconnectDriverSeatOccupied == XPDriverSeatStateOccupied){
377	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>主驾有人，不发4G闭锁");
378	        return;
379	    }
380	    
381	    PLBLEKeyDistanceLevel compareDistanceLevel = PLBLEKeyDistanceLevelEnableCircle;
382	    if (![PLVehicleConfigTool isBleLocationVersionV1]) {
383	        compareDistanceLevel = PLBLEKeyDistanceLevelUnlockCircle;
384	    }
385	    if(self.pollingHandler.distanceLevel <= compareDistanceLevel){
386	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>未超过解锁圈，不发4G闭锁");
387	        return;
388	    }
389	    if (![self.pollingHandler isCanRevealHttpLock]) {
390	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>未超过解锁圈，不发4G闭锁");
391	        return;
392	    }
393	    if(self.isPaused){
394	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>Polling暂停中，不发4G闭锁");
395	        return;
396	    }
397	    DLogTagInfo(kBLEKeyPollingTag, @"<PA>车门未锁，主蓝牙断开连接，不在解锁圈，且主驾无人，4G闭锁");
398	    [self sendPollingBussinessCommand:XPPollingBussiness4GRevertLock];
399	}
