571	                DLogTagInfo(kMultiBleOptTag, @"<PA>发送解锁指令成功，震动");
572	            });
573	        } failed:^(XPVehicleError * error) {
574	            [PLProxyManager.sharedManager.pollingProxy pollingUnlockResultWithIsSuccess:NO];
575	        }];
576	    }
