616	                    DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，声音");
617	                });
618	            }
619	            AudioServicesPlaySystemSoundWithCompletion(kSystemSoundID_Vibrate, ^{
620	                DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，震动");
621	            });
622	            [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:YES];
623	            [self handleStatisticHttpsLockCommandWithSuccess:YES errorCode:PLERRORCODE_default detailErrorCode:0];
624	
625	        } failed:^(XPVehicleError * error) {
