898	- (BOOL)pollingUnlockIfNeed:(PLXPPollingHandler *)pollingHandler {
899	    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
900	        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
901	        return NO;
902	    }
903	    if (pollingHandler.unlockOperateTime != 0) {
904	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但是没有出6秒的限制，返回");
905	        return NO;
906	    }
907	    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateUnlocked) {
908	        DLogTagInfo(kBLEKeyPollingTag, @"车辆是解锁状态，返回,%d", (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]));
909	        return NO;
910	    }
911	    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateDefault) {
912	        if (!self.isRemedy) {
913	            DLogTagInfo(kBLEKeyPollingTag, @"车辆是解锁未知状态，不兜底，返回,%d", (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]));
914	            return NO;
915	        }
916	    }
917	    if ((XPVehicleTempLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"temp_lock_st"]) == XPVehicleTempLockStateActive) {
918	        DLogTagInfo(kBLEKeyPollingTag, @"车辆是临停状态,不解锁，返回,%d", (XPVehicleTempLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"temp_lock_st"]));
919	        return NO;
920	    }
921	
922	    if ((XPVehicleLeaveCarKeepPowerState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"leave_car_keep_power"]) == XPVehicleLeaveCarKeepPowerStateOff ||
923	        (XPVehicleLeaveCarKeepPowerState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"leave_car_keep_power"])  == XPVehicleLeaveCarKeepPowerStateDefault) {
924	        // B件蓝牙会出现车辆状态不返回的情况，为了不影响polling开启，当设防状态未返回时，也允许polling
925	        if ((XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]) == XPAlarmStateDisarmed ||
926	            (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"])  == XPAlarmStateRemind || (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"])  == XPAlarmStateAlarm){
927	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但车辆不是设防状态，返回,%d", (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]) );
928	            return NO;
929	        }
930	        if ((XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]) == XPAlarmStateDefault && !self.isRemedy){
931	            DLogTagInfo(kBLEKeyPollingTag, @"车辆是设防未知状态，返回,%d",  (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]));
932	            return NO;
933	        }
934	    }
935	    
936	    if (self.pollingUnlockTryCount >= 3) {
937	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但超过三次，返回");
938	        return NO;
939	    }
940	    
941	    NSDate *currentTime = [NSDate date];
942	    if(self.prevUnlockCommandTime && [[self.prevUnlockCommandTime dateByAddingTimeInterval:pollingHandler.pollingUnlockInterval] compare:currentTime] == NSOrderedDescending){
943	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但是没有出上一次解锁间隔限制，返回");
944	        return NO;
945	    }
946	    
947	    return YES;
948	}
