971	    }
972	    
973	    NSDate *currentTime = [NSDate date];
974	    if(self.prevLockCommandTime && [[self.prevLockCommandTime dateByAddingTimeInterval:pollingHandler.pollingLockInterval] compare:currentTime] == NSOrderedDescending){
975	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想闭锁，但是没有出上一次闭锁间隔限制，返回");
