    NSDictionary *data = @{@"result" : success?@(1):@(0),
                           @"polling":@(1),
                           @"carType" : [XPVehicleSDK.shared.vehicleManager.currentVehicle.vehiclePreference vehicleTypeCode] ? : @"",
                           @"duration":@([self.class timestamp] - self.httpsLockCommandStartTime),
                           @"channel":@(0),
                           @"connect_status":XPVehicleSDK.shared.vehicleManager.currentVehicle.mqttConnectState == XPMQTTPublisherConnectionStateConnected?@(1):@(0),
                           @"operation":@(0),
                           @"system_bluetooth":XPVehicleSDK.shared.vehicleManager.bleSysState == XPBLESysStatePoweredOn?@(1):@(0),
                           @"system_network":PLXPCTMediatorTool.isNetworkReachable?@(1):@(0),
                           @"error_code":@(errorCode),
                           @"cost_time":@(0),
                           @"lock_type":duoChannel?@(1):@(0),
                           @"detailError_code":@(detailErrorCode),
    };
    [XPStatistics writeMoleEventWithEvent:PLXP_MOBILE_CARCONTROL_LOCK module:PLXP_MOBILE_CARCONTROL_MODULE data:data];
#endif  //XPPollingSDK_Test_Mode
    DLogTagInfo(kStatisticsReportTag, @"module is %@,event is %@",PLXP_MOBILE_CARCONTROL_MODULE,PLXP_MOBILE_CARCONTROL_LOCK);
}

