45	    }
46	    XPVehicleDoorLockState doorState = (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]);
47	    if (doorState == XPVehicleDoorLockStateUnlocked) {
