132	                [self predictUnlock];
133	            } else {
134	                [self predictInCar];
135	            }
136	        } else {
137	            if (self.distanceLevel >= PLBLEKeyDistanceLevelWelcomeCircle) {
138	                [self predictLock];
139	            } else {
140	                int trendResult = [locationResult[@"trendResult"] intValue];
141	                if (trendResult == 0 && self.isConvenient) {
142	                    [self predictUnlock];
143	                }
144	            }
145	        }
