#import "PLXPPollingFirstPollingHandler.h"
#import "PLVehicleStateInstance.h"

#ifdef XPPollingSDK_Test_Mode
#import "PLPolllingTestMockSetting.h"
#else
@import XPVehicleSDK;
#endif  //XPPollingSDK_Test_Mode

@interface PLXPPollingFirstPollingHandler ()


@end

@implementation PLXPPollingFirstPollingHandler
@dynamic delegate;

- (instancetype)init {
    if (self = [super init]) {
        self.pollingLockInterval = 2;
    }
    return self;
}

- (void)initPolling {
    [super initPolling];
}

- (void)deinitPolling {
    [super deinitPolling];
}

- (void)notifyTrunkNeedOpen {
    if (self.distanceLevel == PLBLEKeyDistanceLevelInitCircle) {
        DLogTagInfo(kBLEKeyPollingTag, @"蓝牙圈初始化，返回");
        return;
    }
    XPVehicleDoorLockState doorState = (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]);
    if (doorState == XPVehicleDoorLockStateUnlocked) {
        DLogTagInfo(kBLEKeyPollingTag, @"车辆是解锁状态，不发送后备箱可解锁指令与可闭锁的指令");
        return;
    }
    if (self.distanceLevel <= PLBLEKeyDistanceLevelLockCircle && (self.lastDistanceLevel > PLBLEKeyDistanceLevelLockCircle || self.lastDistanceLevel == PLBLEKeyDistanceLevelInitCircle)) {
        DLogTagInfo(kBLEKeyPollingTag, @"在闭锁内，可以打开后备箱");
        [self predictPollingTrunkEnable];
    } else if (self.distanceLevel > PLBLEKeyDistanceLevelLockCircle && self.lastDistanceLevel <= PLBLEKeyDistanceLevelLockCircle && self.lastDistanceLevel != PLBLEKeyDistanceLevelInitCircle) {
        DLogTagInfo(kBLEKeyPollingTag, @"不在闭锁内，不可以打开后备箱");
        [self predictPollingTrunkDisable];
    }
}

- (void)trunkNeedOpen {
    if ([self.delegate respondsToSelector:@selector(pollingTrunkEnableIfNeed:)]) {
        if ([self.delegate pollingTrunkEnableIfNeed:self]) {
            if ([self.delegate respondsToSelector:@selector(sendTrunckNeedOpenCommand:)]) {
                [self.delegate sendTrunckNeedOpenCommand:self];
            }
        }
    }
}

- (void)trunkNeedNotOpen {
    if ([self.delegate respondsToSelector:@selector(pollingTrunkDisableIfNeed:)]) {
        if ([self.delegate pollingTrunkDisableIfNeed:self]) {
            if ([self.delegate respondsToSelector:@selector(sendTrunckNeedNotOpenCommand:)]) {
                [self.delegate sendTrunckNeedNotOpenCommand:self];
            }
        }
    }
}
#pragma mark — superclass func

- (void)distanceLevelSetterAction {
    [super distanceLevelSetterAction];
    [self notifyTrunkNeedOpen];

    if(self.monitorLock && self.distanceLevel > PLBLEKeyDistanceLevelLockCircle){
        DLogTagInfo(kBLEKeyPollingTag, @"PLogic，解锁圈内上锁，走到连接圈，取消Flag");
        self.operateNativeLockInUnlockRange = NO;
    }

    if (self.monitorUnlock && self.distanceLevel < PLBLEKeyDistanceLevelLockCircle && self.distanceLevel != PLBLEKeyDistanceLevelInitCircle) {
        self.operateNativeUnlockInLockRange = NO;
        if(self.distanceLevel == PLBLEKeyDistanceLevelOneMeterCircle){
            DLogTagInfo(kBLEKeyPollingTag, @"PLogic，连接圈外被解锁，走进解锁圈，取消Flag");
        }
    }
}

- (BOOL)isCanRevealHttpLock {
    if(self.distanceLevel <= PLBLEKeyDistanceLevelEnableCircle){
        return false;
    }
    return true;
}

#pragma mark — XPPollingHandlerProtocol
- (void)handleLocationExtension:(NSDictionary *)locationExtension {
    if (locationExtension[@"rssiRaw"] != nil) {
        NSDictionary *rssiRaw = locationExtension[@"rssiRaw"];
        NSString *rssiStr = nil;
        for (NSString *key in rssiRaw.allKeys) {
            rssiStr = [rssiStr stringByAppendingFormat:@"[%@:%@] ", key, rssiRaw[key]];
        }
        self.locationResultStr = rssiStr;
    }
}

- (void)_handleLocationResult:(NSDictionary *_Nullable)locationResult {
    if (self.distanceLevel == PLBLEKeyDistanceLevelInitCircle) {
        return;
    }
    if (self.distanceLevel == PLBLEKeyDistanceLevelInCar && self.lastDistanceLevel < PLBLEKeyDistanceLevelUnlockCircle) {
        [self predictInCar];
    } else {
        PLBLEKeyDistanceLevel unlockCompareLevel = PLBLEKeyDistanceLevelUnlockCircle;
        if (self.isConvenient) {
            unlockCompareLevel = PLBLEKeyDistanceLevelEnableCircle;
        } else {
            unlockCompareLevel = PLBLEKeyDistanceLevelUnlockCircle;
        }
        if (self.distanceLevel <= unlockCompareLevel) {
            if (self.lastDistanceLevel > PLBLEKeyDistanceLevelInCar || self.lastDistanceLevel == PLBLEKeyDistanceLevelInitCircle) {
                [self predictUnlock];
            } else {
                [self predictInCar];
            }
        } else {
            if (self.distanceLevel >= PLBLEKeyDistanceLevelWelcomeCircle) {
                [self predictLock];
            } else {
                int trendResult = [locationResult[@"trendResult"] intValue];
                if (trendResult == 0 && self.isConvenient) {
                    [self predictUnlock];
                }
            }
        }
    }
}

- (void)predictLock {
    [super predictLock];
    if(self.operateNativeUnlockInLockRange){
        DLogTagInfo(kBLEKeyPollingTag, @"PLogic，操作了主动解锁，不闭锁");
        return;
    }

    if ([self.delegate respondsToSelector:@selector(pollingLockIfNeed:)]) {
        if ([self.delegate pollingLockIfNeed:self]) {
            if ([self.delegate respondsToSelector:@selector(sendPollingLockCommand:)]) {
                [self.delegate sendPollingLockCommand:self];
            }
        }
    }
}

- (void)predictUnlock {
    [super predictUnlock];
    if (self.operateNativeLockInUnlockRange) {
        DLogTagInfo(kBLEKeyPollingTag, @"自动解锁条件 不满足，PLogic，操作了主动上锁，不解锁");
        return;
    }
    if (self.isWatchLocked) {
        DLogTagInfo(kBLEKeyPollingTag, @"自动解锁条件 不满足，被手表上锁，不解锁");
        return;
    }
    if ([self.delegate respondsToSelector:@selector(pollingUnlockIfNeed:)]) {
        if ([self.delegate pollingUnlockIfNeed:self]) {
            if ([self.delegate respondsToSelector:@selector(sendPollingUnlockCommand:)]) {
                [self.delegate sendPollingUnlockCommand:self];
            }
        }
    }
}

- (void)predictInCar {
    [super predictInCar];
    DLogTagInfo(kBLEKeyPollingTag, @"定位在车内，不执行任何动作");
}

- (void)predictPollingTrunkEnable {
    [super predictPollingTrunkEnable];
    if (self.isWatchLocked) {
        DLogTagInfo(kBLEKeyPollingTag, @"被手表上锁，不可以解锁后备箱");
        return;
    }
    [self trunkNeedOpen];
}

- (void)predictPollingTrunkDisable {
    [super predictPollingTrunkDisable];
    [self trunkNeedNotOpen];
}

- (void)pollingLockCommandDidSuccess {
}

- (void)detectCarIsLocked {
    PLBLEKeyDistanceLevel compareLevel = PLBLEKeyDistanceLevelEnableCircle;
    if (!self.isConvenient) {
        compareLevel = PLBLEKeyDistanceLevelUnlockCircle;
    }
    if(self.distanceLevel <= compareLevel && self.distanceLevel != PLBLEKeyDistanceLevelInitCircle){
        DLogTagInfo(kBLEKeyPollingTag, @"PLogic，检测到车解锁圈内上锁");
//        [[XPBLEKeepAliveBussiness sharedInstance] remoteOtherMsg:@"PLogic，检测到车解锁圈内上锁"];
        self.operateNativeLockInUnlockRange = YES;
    }
    if (self.distanceLevel != PLBLEKeyDistanceLevelInitCircle) {
        self.unlockOperateTime = arc4random() % 3 + 6;
    }
}

- (void)detectCarIsUnlocked {
    [super detectCarIsUnlocked];
    if(self.distanceLevel > PLBLEKeyDistanceLevelLockCircle){
        DLogTagInfo(kBLEKeyPollingTag, @"PLogic，检测到车闭锁圈外解锁");
//        [[XPBLEKeepAliveBussiness sharedInstance] remoteOtherMsg:@"PLogic，检测到车闭锁圈外解锁"];
        self.operateNativeUnlockInLockRange = YES;
    }
    if (self.distanceLevel != PLBLEKeyDistanceLevelInitCircle) {
        self.lockOperateTime = arc4random() % 3 + 6;
    }
    [self trunkNeedNotOpen];
}

- (void)detectBleConnect:(BOOL)inBluetoothSession {
    [self resetNativeFlags];
    self.distanceLevel = PLBLEKeyDistanceLevelInitCircle;
    self.lastDistanceLevel = PLBLEKeyDistanceLevelInitCircle;
}

- (void)detectBleRetryDisconnect {
    [super detectBleRetryDisconnect];
}

- (void)resetNativeFlags {
    [super resetNativeFlags];
}

- (void)forceDisableAllEnableCmd {
    [self trunkNeedNotOpen];
}

#pragma mark — setter & getter
- (void)setIsWatchLocked:(BOOL)isWatchLocked {
    [super setIsWatchLocked:isWatchLocked];
    if (isWatchLocked) {
        [self forceDisableAllEnableCmd];
    }
}

- (void)setOperateNativeLockInUnlockRange:(BOOL)operateNativeLockInUnlockRange {
    [super setOperateNativeLockInUnlockRange:operateNativeLockInUnlockRange];
    self.monitorLock = NO;
    if(operateNativeLockInUnlockRange){
        self.monitorLock = YES;
    }
}

- (void)setOperateNativeUnlockInLockRange:(BOOL)operateNativeUnlockInLockRange{
    [super setOperateNativeUnlockInLockRange:operateNativeUnlockInLockRange];
    self.monitorUnlock = NO;
    if(operateNativeUnlockInLockRange){
        self.monitorUnlock = YES;
        DLogTagInfo(kBLEKeyPollingTag, @"PLogic，解锁圈外被解锁，不闭锁");
    }
}

@end

