542	- (void)configBLEInfo {
543	#ifdef XPPollingSDK_Test_Mode
544	    NSDictionary * bleHardInfoMap = [[PLPolllingTestMockSetting getOTABleHardMap]valueForKey:PLPolllingTestMockSetting.vehicleTypeName ? : @""];
545	#else
546	    NSDictionary * bleHardInfoMap = [[PLPollingEffectDataManager.sharedManager getKeySettingData].bleHardMap valueForKey:PLXPCTMediatorTool.vehicleTypeName];
547	#endif //XPPollingSDK_Test_Mode
548	    [[PLXPBLEInfoManager manager] start:bleHardInfoMap];
549	}
550	
551	- (void)judgePollingIsPaused {
552	    if (self.isPollingCalibration || self.isInParkingProcess || self.isAutoParking || !self.gearValueIsSupportPolling || self.isSleepMode) {
553	        DLogTagInfo(kMultiBleOptTag, @"polling服务要暂停:isPollingCalibration:%d,isInParkingProcess:%d,isAutoParking:%d,gearValueIsSupportPolling:%d,isSleepMode:%d",self.isPollingCalibration,self.isInParkingProcess,self.isAutoParking,self.gearValueIsSupportPolling,self.isSleepMode);
554	        if ([self.blePollingLifeManager respondsToSelector:@selector(pauseBlePolling)]) {
555	            [self.blePollingLifeManager pauseBlePolling];
556	        }
557	        return;
558	    }
559	    DLogTagInfo(kMultiBleOptTag, @"polling服务要恢复");
560	    if ([self.blePollingLifeManager respondsToSelector:@selector(remuseBlePolling)]) {
561	        [self.blePollingLifeManager remuseBlePolling];
562	    }
563	}
564	
565	- (void)judgeBleLocationIsPaused {
566	    if ([PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode == PLPollingRunModeNone && self.pollingAndLocationIsBind) {
567	        DLogTagInfo(kMultiBleOptTag, @"predict服务要暂停,PLPollingRunMode:%d,pollingAndLocationIsBind:%d", [PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode, self.pollingAndLocationIsBind);
568	        if ([self.bleLocationLifeManager respondsToSelector:@selector(pauseBleLocation)]) {
569	            [self.bleLocationLifeManager pauseBleLocation];
570	        }
571	        return;
572	    }
573	    if (!self.gearValueIsSupportLocation) {
574	        if (!self.drivingNeedLocation && !self.isInParkingController && !self.isPollingCalibration) {
575	            DLogTagInfo(kMultiBleOptTag, @"predict服务要暂停,gearValueIsSupportLocation:%d",self.gearValueIsSupportLocation);
576	            if ([self.bleLocationLifeManager respondsToSelector:@selector(pauseBleLocation)]) {
577	                [self.bleLocationLifeManager pauseBleLocation];
578	            }
579	            return;
580	        }
