- (void)judgePollingIsPaused {
    if (self.isPollingCalibration || self.isInParkingProcess || self.isAutoParking || !self.gearValueIsSupportPolling || self.isSleepMode) {
        DLogTagInfo(kMultiBleOptTag, @"polling服务要暂停:isPollingCalibration:%d,isInParkingProcess:%d,isAutoParking:%d,gearValueIsSupportPolling:%d,isSleepMode:%d",self.isPollingCalibration,self.isInParkingProcess,self.isAutoParking,self.gearValueIsSupportPolling,self.isSleepMode);
        if ([self.blePollingLifeManager respondsToSelector:@selector(pauseBlePolling)]) {
            [self.blePollingLifeManager pauseBlePolling];
        }
        return;
    }
    DLogTagInfo(kMultiBleOptTag, @"polling服务要恢复");
    if ([self.blePollingLifeManager respondsToSelector:@selector(remuseBlePolling)]) {
        [self.blePollingLifeManager remuseBlePolling];
    }
}

- (void)judgeBleLocationIsPaused {
    if ([PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode == PLPollingRunModeNone && self.pollingAndLocationIsBind) {
        DLogTagInfo(kMultiBleOptTag, @"predict服务要暂停,PLPollingRunMode:%d,pollingAndLocationIsBind:%d", [PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode, self.pollingAndLocationIsBind);
        if ([self.bleLocationLifeManager respondsToSelector:@selector(pauseBleLocation)]) {
            [self.bleLocationLifeManager pauseBleLocation];
        }
        return;
    }
    if (!self.gearValueIsSupportLocation) {
        if (!self.drivingNeedLocation && !self.isInParkingController && !self.isPollingCalibration) {
            DLogTagInfo(kMultiBleOptTag, @"predict服务要暂停,gearValueIsSupportLocation:%d",self.gearValueIsSupportLocation);
            if ([self.bleLocationLifeManager respondsToSelector:@selector(pauseBleLocation)]) {
                [self.bleLocationLifeManager pauseBleLocation];
            }
            return;
        }
    }
    DLogTagInfo(kMultiBleOptTag, @"predict服务要恢复");
    if ([self.bleLocationLifeManager respondsToSelector:@selector(remuseBleLocation)]) {
        [self.bleLocationLifeManager remuseBleLocation];
    }
}

